// ✏️ EDITE AQUI as hashtags de busca por nicho
const buscas = [
  // Cirurgia Plástica
  { nicho: 'Cirurgia Plástica', hashtag: 'cirurgiaplastica' },
  { nicho: 'Cirurgia Plástica', hashtag: 'cirurgiaestetica' },
  { nicho: 'Cirurgia Plástica', hashtag: 'plasticsurgery' },

  // Ortopedia da Coluna
  { nicho: 'Ortopedia da Coluna', hashtag: 'ortopedia' },
  { nicho: 'Ortopedia da Coluna', hashtag: 'dorcostas' },
  { nicho: 'Ortopedia da Coluna', hashtag: 'coluna' },

  // Harmonização Facial
  { nicho: 'Harmonização Facial', hashtag: 'harmonizacaofacial' },
  { nicho: 'Harmonização Facial', hashtag: 'fullface' },
  { nicho: 'Harmonização Facial', hashtag: 'bichectomia' },

  // Dermatologia
  { nicho: 'Dermatologia', hashtag: 'dermatologia' },
  { nicho: 'Dermatologia', hashtag: 'pele' },
  { nicho: 'Dermatologia', hashtag: 'skincare' },

  // Psicologia
  { nicho: 'Psicologia', hashtag: 'psicologia' },
  { nicho: 'Psicologia', hashtag: 'saudemental' },
  { nicho: 'Psicologia', hashtag: 'terapia' }
];

return buscas.map(b => ({ json: b }));

// Extrai os dados relevantes de cada resposta da API
const buscaOriginal = $('Preparar Buscas').item.json;
const nicho = buscaOriginal.nicho;
const hashtag = buscaOriginal.hashtag;

const resposta = $input.item.json;
const videos =
  resposta.data?.videos ||
  resposta.videos ||
  resposta.itemList ||
  resposta.items ||
  [];

if (!Array.isArray(videos) || videos.length === 0) {
  console.log(`Sem vídeos para #${hashtag}`);
  return [];
}

const formatados = videos.slice(0, 5).map(v => {
  const autor =
    v.author?.uniqueId ||
    v.authorMeta?.name ||
    v.author?.nickname ||
    '⚠️ NOT AVAILABLE';

  const videoId = v.id || v.videoId || '';
  const link = videoId
    ? `https://www.tiktok.com/@${autor}/video/${videoId}`
    : '⚠️ NOT AVAILABLE';

  return {
    nicho,
    hashtag,
    link,
    autor,
    views:       v.stats?.playCount    ?? v.playCount    ?? v.statistics?.playCount    ?? '⚠️ NOT AVAILABLE',
    likes:       v.stats?.diggCount    ?? v.diggCount    ?? v.statistics?.diggCount    ?? '⚠️ NOT AVAILABLE',
    comentarios: v.stats?.commentCount ?? v.commentCount ?? v.statistics?.commentCount ?? '⚠️ NOT AVAILABLE',
    descricao:   v.desc || v.description || v.title || '⚠️ NOT AVAILABLE',
    data: v.createTime
      ? new Date(v.createTime * 1000).toLocaleDateString('pt-BR')
      : '⚠️ NOT AVAILABLE'
  };
});

return formatados.map(v => ({ json: v }));

// Agrupa por nicho, remove duplicatas e monta o texto final
const todos = $input.item.json.data || [];

const porNicho = {};
for (const v of todos) {
  if (!porNicho[v.nicho]) porNicho[v.nicho] = [];
  const duplicado = porNicho[v.nicho].some(x => x.link === v.link);
  if (!duplicado && v.link !== '⚠️ NOT AVAILABLE') {
    porNicho[v.nicho].push(v);
  }
}

const hoje = new Date().toLocaleDateString('pt-BR');
const hojeISO = new Date().toISOString().split('T')[0];
let texto = `# Dados TikTok — ${hoje}\n\n`;
let totalVideos = 0;

const ordem = [
  'Cirurgia Plástica',
  'Ortopedia da Coluna',
  'Harmonização Facial',
  'Dermatologia',
  'Psicologia'
];

for (const nicho of ordem) {
  const videos = porNicho[nicho] || [];
  texto += `## ${nicho}\n\n`;

  if (videos.length === 0) {
    texto += `⚠️ Nenhum vídeo coletado para este nicho.\n\n`;
    continue;
  }

  videos.forEach((v, i) => {
    texto += `### Vídeo ${i + 1}\n`;
    texto += `🔗 ${v.link}\n`;
    texto += `👤 @${v.autor}\n`;
    texto += `📊 ${v.views} views | ${v.likes} likes | ${v.comentarios} comentários\n`;
    texto += `📝 ${v.descricao}\n`;
    texto += `📅 ${v.data}\n\n`;
    totalVideos++;
  });
}

return [{ json: { texto, data: hoje, hojeISO, totalVideos } }];

// Converte o texto em arquivo binário para enviar ao Google Drive
const texto = $input.item.json.texto;
const hojeISO = $input.item.json.hojeISO;
const fileName = `vistto-tiktok-${hojeISO}.md`;

const buffer = Buffer.from(texto, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(
  buffer,
  fileName,
  'text/plain'
);

return [{
  json: { ...$input.item.json, fileName },
  binary: { arquivo: binaryData }
}];
